<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('licenses.view');use VP3\Licensing\LicenseService;$id=(int)vp3_input('id');$issued=null;if(vp3_method()==='POST'){vp3_require_admin_permission('licenses.manage');vp3_verify_csrf();$action=vp3_input('action');if($id&&in_array($action,['active','suspended','revoked','expired','development'],true)){vp3_db()->prepare('UPDATE licenses SET status=?,updated_at=NOW() WHERE id=?')->execute([$action,$id]);vp3_audit('admin',(int)$admin['id'],'license.status_updated','license',(string)$id,['status'=>$action]);vp3_redirect('admin/license.php?id='.$id);}if(!$id&&$action==='issue'){$domains=array_values(array_filter(array_map('trim',preg_split('/[\r\n,]+/',vp3_input('domains'))?:[])));$service=new LicenseService(vp3_db());$issued=$service->issue(['customer_id'=>(int)vp3_input('customer_id'),'product_id'=>(int)vp3_input('product_id'),'plan_id'=>(int)vp3_input('plan_id'),'edition'=>vp3_input('edition','standard'),'status'=>'active','max_activations'=>(int)vp3_input('max_activations','1'),'expires_at'=>vp3_input('expires_at'),'updates_until'=>vp3_input('updates_until'),'domains'=>$domains]);}}
$customers=vp3_db()->query("SELECT id,name,email FROM customers WHERE status='active' ORDER BY name")->fetchAll();$products=vp3_db()->query("SELECT id,name FROM products WHERE status='active' ORDER BY name")->fetchAll();$plans=vp3_db()->query("SELECT id,name,product_id FROM product_plans WHERE status='active' ORDER BY name")->fetchAll();$row=null;$domains=[];$acts=[];if($id){$s=vp3_db()->prepare('SELECT l.*,c.name customer_name,p.name product_name FROM licenses l JOIN customers c ON c.id=l.customer_id JOIN products p ON p.id=l.product_id WHERE l.id=?');$s->execute([$id]);$row=$s->fetch();$s=vp3_db()->prepare('SELECT * FROM license_domains WHERE license_id=? ORDER BY id');$s->execute([$id]);$domains=$s->fetchAll();$s=vp3_db()->prepare('SELECT installation_uuid,domain,product_version,status,activated_at,last_validated_at FROM license_activations WHERE license_id=? ORDER BY id DESC');$s->execute([$id]);$acts=$s->fetchAll();}$pageTitle=$id?'License':'Issue License';require VP3_ROOT.'/includes/admin-header.php';?><?php if($issued):?><div class="flash success"><strong>Copy this license key now. It will not be stored in plain text:</strong><br><code><?=vp3_e($issued['license_key'])?></code></div><?php endif;?><?php if($row):?><h1><?=vp3_e($row['product_name'])?> license</h1><div class="grid two"><article class="card"><p>Customer: <?=vp3_e($row['customer_name'])?></p><p>Key: <?=vp3_e($row['license_key_prefix'])?>… · <?=vp3_e($row['license_fingerprint'])?></p><p>Edition: <?=vp3_e($row['edition'])?></p><p>Expires: <?=vp3_e($row['expires_at']?:'Never')?> · Updates: <?=vp3_e($row['updates_until']?:'Not set')?></p></article><form class="card" method="post"><?=vp3_csrf_field()?><div class="field"><label>Status action</label><select name="action"><?php foreach(['active','suspended','revoked','expired','development'] as $st):?><option <?=$row['status']===$st?'selected':''?>><?=$st?></option><?php endforeach;?></select></div><button class="button">Update license</button></form></div><h2>Authorized domains</h2><div class="table-wrap"><table class="table"><?php foreach($domains as $d):?><tr><td><?=vp3_e($d['domain'])?></td><td><?=vp3_e($d['domain_type'])?></td><td><span class="badge <?=vp3_e($d['status'])?>"><?=vp3_e($d['status'])?></span></td></tr><?php endforeach;?></table></div><h2>Activations</h2><div class="table-wrap"><table class="table"><thead><tr><th>Installation</th><th>Domain</th><th>Version</th><th>Status</th><th>Last validated</th></tr></thead><tbody><?php foreach($acts as $a):?><tr><td><?=vp3_e($a['installation_uuid'])?></td><td><?=vp3_e($a['domain'])?></td><td><?=vp3_e($a['product_version'])?></td><td><?=vp3_e($a['status'])?></td><td><?=vp3_e($a['last_validated_at'])?></td></tr><?php endforeach;?></tbody></table></div><?php else:?><h1>Issue a secure license</h1><form class="card" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="issue"><div class="grid two"><div class="field"><label>Customer</label><select name="customer_id" required><?php foreach($customers as $c):?><option value="<?=(int)$c['id']?>"><?=vp3_e($c['name'].' · '.$c['email'])?></option><?php endforeach;?></select></div><div class="field"><label>Product</label><select name="product_id" required><?php foreach($products as $p):?><option value="<?=(int)$p['id']?>"><?=vp3_e($p['name'])?></option><?php endforeach;?></select></div><div class="field"><label>Plan</label><select name="plan_id"><option value="0">No plan</option><?php foreach($plans as $p):?><option value="<?=(int)$p['id']?>"><?=vp3_e($p['name'])?></option><?php endforeach;?></select></div><div class="field"><label>Edition</label><input name="edition" value="standard" required></div><div class="field"><label>Maximum activations</label><input name="max_activations" type="number" min="1" value="1" required></div><div class="field"><label>Expiration</label><input name="expires_at" type="date"></div><div class="field"><label>Updates through</label><input name="updates_until" type="date"></div></div><div class="field"><label>Authorized domains</label><textarea name="domains" placeholder="example.com&#10;staging.example.com" required></textarea></div><button class="button">Generate license</button></form><?php endif;?><?php require VP3_ROOT.'/includes/admin-footer.php';?>